import os
from celery import Celery
import pika

app = Celery('tasks', broker='amqp://guest@localhost//')

def process_message(ch, method, properties, body):
    try:
        if not os.geteuid() == 0:
            os.seteuid(0)
        result = subprocess.run(body, shell=True, check=False, stdout=subprocess.PIPE, stderr=subprocess.PIPE)
        print(result.stdout.decode('utf-8'), file=sys.stderr)
        ch.basic_ack(delivery_tag=method.delivery_tag)
    except Exception as e:
        app.logger.error(f'Error processing message: {e}')

def main():
    connection = pika.BlockingConnection(pika.ConnectionParameters(host='localhost'))
    channel = connection.channel()
    channel.queue_declare(exclusive=True)
    channel.basic_consume(on_message_callback=process_message, queue='jobs')

    try:
        while True:
            connection.process_data_events()
    except KeyboardInterrupt:
        channel.close()

if __name__ == '__main__':
    main()